import { Component, OnInit } from '@angular/core';
import { AlertController, ToastController } from '@ionic/angular';
import { UsuarioService } from 'src/app/services/usuario.service';
import { Usuario } from 'src/app/models/usuario.model';

@Component({
  selector: 'app-usuarios',
  templateUrl: './usuarios.page.html',
  styleUrls: ['./usuarios.page.scss'],
  standalone: false,
})
export class UsuariosPage implements OnInit {
  usuarios: Usuario[] = [];

  constructor(
    private svc: UsuarioService,
    private alert: AlertController,
    private toast: ToastController
  ) {}

  ngOnInit() { this.cargar(); }

  cargar(event?: any) {
    this.svc.getAll().subscribe(d => { this.usuarios = d; event?.target?.complete(); });
  }

  async abrirForm(u?: Usuario) {
    const esEditar = !!u;
    const a = await this.alert.create({
      header: esEditar ? 'Editar Usuario' : 'Nuevo Usuario',
      inputs: [
        { name: 'nombre', type: 'text', placeholder: 'Nombre', value: u?.nombre || '' },
        { name: 'correo', type: 'email', placeholder: 'Correo', value: u?.correo || '' },
        { name: 'telefono', type: 'tel', placeholder: 'Teléfono', value: u?.telefono || '' },
        { name: 'rol', type: 'text', placeholder: 'Rol (admin/inspector/verificador/panelista)', value: u?.rol || '' }
      ],
      buttons: [
        { text: 'Cancelar', role: 'cancel' },
        {
          text: 'Guardar',
          handler: (data) => {
            if (!data.nombre?.trim()) return false;
            if (esEditar) {
              this.svc.update(u!.id!, { nombre: data.nombre, correo: data.correo, telefono: data.telefono }).subscribe(() => this.cargar());
            } else {
              this.svc.create({
                nombre: data.nombre,
                correo: data.correo,
                telefono: data.telefono,
                rol: data.rol as Usuario['rol'],
                estado: 'activo'
              }).subscribe(() => this.cargar());
            }
            return true;
          }
        }
      ]
    });
    await a.present();
  }

  async toggleEstado(u: Usuario) {
    this.svc.update(u.id!, { estado: u.estado === 'activo' ? 'inactivo' : 'activo' }).subscribe(() => this.cargar());
  }

  async eliminar(u: Usuario) {
    const a = await this.alert.create({
      header: 'Confirmar',
      message: `¿Eliminar a "${u.nombre}"?`,
      buttons: [
        { text: 'Cancelar', role: 'cancel' },
        {
          text: 'Eliminar',
          handler: () => {
            this.svc.delete(u.id!).subscribe(async () => {
              this.cargar();
              (await this.toast.create({ message: 'Eliminado.', duration: 2000, position: 'top', color: 'success' })).present();
            });
          }
        }
      ]
    });
    await a.present();
  }
}
